import { ChildProcess, spawn } from "node:child_process";
import type { JsonRpcRequest, JsonRpcNotification, JsonRpcResponse } from "../types.ts";

export interface ConnectionEvents {
	onResponse: (msg: JsonRpcResponse) => void;
	onNotification: (method: string, params: unknown) => void;
	onError: (error: Error) => void;
	onClose: () => void;
}

export class Connection {
	private proc: ChildProcess | null = null;
	private buffer = "";
	private nextId = 1;
	private pending = new Map<number | string, { resolve: (value: unknown) => void; reject: (error: Error) => void }>();
	private handlers: ConnectionEvents;
	private closed = false;

	constructor(handlers: ConnectionEvents) {
		this.handlers = handlers;
	}

	get isClosed(): boolean {
		return this.closed;
	}

	start(command: string[], cwd: string): void {
		this.proc = spawn(command[0], command.slice(1), {
			cwd,
			stdio: ["pipe", "pipe", "pipe"],
		});

		this.proc.stdout?.on("data", (chunk: Buffer) => {
			this.buffer += chunk.toString("utf-8");
			this.parseMessages();
		});

		this.proc.stderr?.on("data", (chunk: Buffer) => {
			// LSP servers log to stderr; ignore or forward
			void chunk;
		});

		this.proc.on("error", (err) => {
			this.handlers.onError(err);
		});

		this.proc.on("close", () => {
			this.closed = true;
			for (const [id, pending] of this.pending) {
				pending.reject(new Error(`Connection closed (pending request ${id})`));
			}
			this.pending.clear();
			this.handlers.onClose();
		});
	}

	sendRequest(method: string, params?: unknown): Promise<unknown> {
		return new Promise((resolve, reject) => {
			if (this.closed || !this.proc?.stdin?.writable) {
				reject(new Error("Connection is closed"));
				return;
			}
			const id = this.nextId++;
			const msg: JsonRpcRequest = { jsonrpc: "2.0", id, method, params };
			this.pending.set(id, { resolve, reject });
			this.write(msg);
		});
	}

	sendNotification(method: string, params?: unknown): void {
		if (this.closed || !this.proc?.stdin?.writable) return;
		const msg: JsonRpcNotification = { jsonrpc: "2.0", method, params };
		this.write(msg);
	}

	private write(msg: JsonRpcRequest | JsonRpcNotification): void {
		const body = JSON.stringify(msg);
		const header = `Content-Length: ${Buffer.byteLength(body, "utf-8")}\r\n\r\n`;
		this.proc!.stdin!.write(header + body, "utf-8");
	}

	private parseMessages(): void {
		while (this.buffer.length > 0) {
			const headerEnd = this.buffer.indexOf("\r\n\r\n");
			if (headerEnd === -1) break;

			const header = this.buffer.substring(0, headerEnd);
			const match = header.match(/^Content-Length:\s*(\d+)/i);
			if (!match) {
				this.buffer = this.buffer.substring(headerEnd + 4);
				continue;
			}

			const contentLength = Number.parseInt(match[1], 10);
			const bodyStart = headerEnd + 4;
			const bodyEnd = bodyStart + contentLength;

			if (this.buffer.length < bodyEnd) break;

			const body = this.buffer.substring(bodyStart, bodyEnd);
			this.buffer = this.buffer.substring(bodyEnd);

			try {
				const msg = JSON.parse(body) as JsonRpcResponse;
				if ("id" in msg && ("result" in msg || "error" in msg)) {
					const pending = this.pending.get(msg.id);
					if (pending) {
						this.pending.delete(msg.id);
						if (msg.error) {
							pending.reject(new Error(`LSP error ${msg.error.code}: ${msg.error.message}`));
						} else {
							pending.resolve(msg.result);
						}
					}
					this.handlers.onResponse(msg);
				} else if ("method" in msg) {
					this.handlers.onNotification((msg as unknown as { method: string }).method, (msg as unknown as { params?: unknown }).params);
				}
			} catch {
				// Ignore malformed messages
			}
		}
	}

	kill(): void {
		this.closed = true;
		for (const [, pending] of this.pending) {
			pending.reject(new Error("Connection killed"));
		}
		this.pending.clear();
		this.proc?.kill();
		this.proc = null;
	}
}

