import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { registerPiDebug } from "./src/extension/register.ts";

export default function (pi: ExtensionAPI): void {
	registerPiDebug(pi);
}

// ─── DAP Protocol Types ───────────────────────────────────────────────

/** JSON-RPC 2.0 request envelope used by DAP. */
export interface DAPRequest {
	jsonrpc: "2.0";
	id: number;
	method: string;
	params?: Record<string, unknown>;
}

/** JSON-RPC 2.0 success response. */
export interface DAPSuccessResponse {
	jsonrpc: "2.0";
	id: number;
	result: Record<string, unknown>;
}

/** JSON-RPC 2.0 error response. */
export interface DAPErrorResponse {
	jsonrpc: "2.0";
	id: number;
	error: {
		code: number;
		message: string;
		data?: unknown;
	};
}

/** JSON-RPC 2.0 response (success or error). */
export type DAPResponse = DAPSuccessResponse | DAPErrorResponse;

/** JSON-RPC 2.0 notification (event). */
export interface DAPNotification {
	jsonrpc: "2.0";
	method: string;
	params?: Record<string, unknown>;
}

/** Any inbound DAP message. */
export type DAPMessage = DAPResponse | DAPNotification;

// ─── DAP Capability Types ─────────────────────────────────────────────

export interface DAPCapabilities {
	supportsConfigurationDoneRequest?: boolean;
	supportsFunctionBreakpoints?: boolean;
	supportsConditionalBreakpoints?: boolean;
	supportsHitConditionalBreakpoints?: boolean;
	supportsEvaluateForHovers?: boolean;
	supportsStepBack?: boolean;
	supportsSetVariable?: boolean;
	supportsRestartFrame?: boolean;
	supportsGotoTargetsRequest?: boolean;
	supportsStepInTargetsRequest?: boolean;
	supportsCompletionsRequest?: boolean;
	supportsModulesRequest?: boolean;
	supportsRestartRequest?: boolean;
	supportsExceptionOptions?: boolean;
	supportsValueFormattingOptions?: boolean;
	supportsExceptionInfoRequest?: boolean;
	supportTerminateDebuggee?: boolean;
	supportsDelayedStackTraceLoading?: boolean;
	supportsLoadedSourcesRequest?: boolean;
	supportsLogPoints?: boolean;
	supportsTerminateThreadsRequest?: boolean;
	supportsSetExpression?: boolean;
	supportsTerminatedRequest?: boolean;
	supportsDataBreakpoints?: boolean;
	supportsReadMemoryRequest?: boolean;
	supportsWriteMemoryRequest?: boolean;
	supportsDisassembleRequest?: boolean;
	supportsCancelRequest?: boolean;
	supportsBreakpointLocationsRequest?: boolean;
	supportsClipboardContext?: boolean;
	supportsSteppingGranularity?: boolean;
	supportsInstructionBreakpoints?: boolean;
	supportsExceptionFilterOptions?: boolean;
	supportsSingleThreadExecutionRequests?: boolean;
}

// ─── DAP Semantic Types ──────────────────────────────────────────────

export interface Source {
	name?: string;
	path?: string;
	sourceReference?: number;
	presentationHint?: "normal" | "emphasize" | "deemphasize";
	origin?: string;
	adapters?: unknown[];
	checksums?: Array<{ algorithm: string; checksum: string }>;
}

export interface Breakpoint {
	id?: number;
	verified: boolean;
	message?: string;
	source?: Source;
	line?: number;
	column?: number;
	endLine?: number;
	endColumn?: number;
}

export interface StackFrame {
	id: number;
	name: string;
	source?: Source;
	line: number;
	column: number;
	endLine?: number;
	endColumn?: number;
	canRestart?: boolean;
	presentationHint?: "normal" | "label" | "subtle";
	moduleId?: number | string;
}

export interface Thread {
	id: number;
	name: string;
}

export interface Scope {
	name: string;
	variablesReference: number;
	namedVariables?: number;
	indexedVariables?: number;
	expensive: boolean;
	source?: Source;
	line?: number;
	column?: number;
	endLine?: number;
	endColumn?: number;
}

export interface Variable {
	name: string;
	value: string;
	type?: string;
	variablesReference: number;
	namedVariables?: number;
	indexedVariables?: number;
	evaluateName?: string;
	memoryReference?: string;
	presentationHint?: VariablePresentationHint;
}

export interface VariablePresentationHint {
	kind?: string;
	attributes?: string[];
	visibility?: "public" | "private" | "protected" | "internal" | "protected internal" | "private protected";
	lazy?: boolean;
}

export interface EvaluateResponse {
	result: string;
	type?: string;
	variablesReference: number;
	namedVariables?: number;
	indexedVariables?: number;
	memoryReference?: string;
	presentationHint?: VariablePresentationHint;
}

// ─── DAP Event Types ─────────────────────────────────────────────────

export interface StoppedEvent {
	reason: string;
	description?: string;
	threadId?: number;
	preserveFocusHint?: boolean;
	text?: string;
	allThreadsStopped?: boolean;
	hitBreakpointIds?: number[];
}

export interface ContinuedEvent {
	threadId: number;
	allThreadsContinued?: boolean;
}

export interface TerminatedEvent {
	restart?: boolean;
}

export interface ThreadEvent {
	reason: "started" | "exited";
	threadId: number;
}

export interface OutputEvent {
	category?: string;
	output: string;
	variablesReference?: number;
	source?: Source;
	line?: number;
	column?: number;
	data?: unknown;
}

// ─── Configuration Types ─────────────────────────────────────────────

export interface AdapterConfig {
	language: string;
	command: string[];
	adapter: string;
	extensions: string[];
	detectionFiles: string[];
	transport: "stdio" | "tcp";
	port?: number;
	host?: string;
	enabled?: boolean;
}

