	| "shutting_down"
	| "terminated";

import { readFileSync, existsSync } from "node:fs";
import { join } from "node:path";
import type { PiDebugConfig } from "./types.ts";

const DEFAULT_CONFIG: PiDebugConfig = {
	enabled: true,
	autoSuggest: true,
	defaultAdapter: "auto",
	stopOnEntry: true,
	maxStackFrames: 50,
	maxVariableDepth: 3,
	timeout: 30000,
	adapters: {
		node: { enabled: true },
		python: { enabled: true },
	},
};

export interface LoadedConfig {
	config: PiDebugConfig;
	path: string | null;
}

export function loadConfig(cwd: string): LoadedConfig {
	const configPath = join(cwd, ".pi", "pi-debug.json");

	if (!existsSync(configPath)) {
		return { config: { ...DEFAULT_CONFIG }, path: null };
	}

	try {
		const raw = readFileSync(configPath, "utf-8");
		const parsed = JSON.parse(raw) as Partial<PiDebugConfig>;
		return {
			config: { ...DEFAULT_CONFIG, ...parsed },
			path: configPath,
		};
	} catch {
		return { config: { ...DEFAULT_CONFIG }, path: configPath };
	}
}

import { ChildProcess, spawn } from "node:child_process";
import { createConnection as createTcpConnection, Socket } from "node:net";
import type { DAPRequest, DAPResponse, DAPNotification, DAPMessage } from "../types.ts";

export interface ConnectionEvents {
	onResponse: (msg: DAPResponse) => void;
	onEvent: (method: string, params: Record<string, unknown>) => void;
	onError: (error: Error) => void;
	onClose: () => void;
}

/**
 * DAP transport supporting both stdio (Content-Length framing) and TCP.
 * DAP uses the same Content-Length framing as LSP over stdio.
 */
export class Connection {
	private proc: ChildProcess | null = null;
	private socket: Socket | null = null;
	private buffer = "";
	private nextId = 1;
	private pending = new Map<number, { resolve: (value: Record<string, unknown>) => void; reject: (error: Error) => void }>();
	private handlers: ConnectionEvents;
	private closed = false;
	private transport: "stdio" | "tcp" = "stdio";

	constructor(handlers: ConnectionEvents) {
		this.handlers = handlers;
	}

	get isClosed(): boolean {
		return this.closed;
	}

	get transportType(): "stdio" | "tcp" {
		return this.transport;
	}

	/** Start a stdio-based debug adapter as a child process. */
	startStdio(command: string[], cwd: string, env?: Record<string, string>): void {
		this.transport = "stdio";
		this.proc = spawn(command[0], command.slice(1), {
			cwd,
			stdio: ["pipe", "pipe", "pipe"],
			env: { ...process.env, ...env },
		});

		this.proc.stdout?.on("data", (chunk: Buffer) => {
			this.buffer += chunk.toString("utf-8");
			this.parseMessages();
		});

		this.proc.stderr?.on("data", (chunk: Buffer) => {
			// Debug adapters log to stderr; ignore or forward
			void chunk;
		});

		this.proc.on("error", (err) => {
			this.handlers.onError(err);
		});

		this.proc.on("close", () => {
			this.handleClose();
		});
	}

	/** Connect to a TCP-based debug adapter. */
	connectTcp(host: string, port: number): Promise<void> {
		this.transport = "tcp";
		return new Promise((resolve, reject) => {
			this.socket = createTcpConnection({ host, port }, () => {
				resolve();
			});

			this.socket.on("data", (chunk: Buffer) => {
				this.buffer += chunk.toString("utf-8");
				this.parseMessages();
			});

			this.socket.on("error", (err) => {
				this.handlers.onError(err);
				reject(err);
			});

			this.socket.on("close", () => {
				this.handleClose();
			});
		});
	}

	/** Send a DAP request and return a promise for the result. */
	sendRequest(method: string, params?: Record<string, unknown>): Promise<Record<string, unknown>> {
		return new Promise((resolve, reject) => {
			if (this.closed) {
				reject(new Error("Connection is closed"));
				return;
			}

			const id = this.nextId++;
			const msg: DAPRequest = { jsonrpc: "2.0", id, method, params };
			this.pending.set(id, { resolve, reject });
			this.write(msg);
		});
	}

	/** Send a DAP notification (no response expected). */
	sendNotification(method: string, params?: Record<string, unknown>): void {
		if (this.closed) return;
		const msg: DAPNotification = { jsonrpc: "2.0", method, params };
		this.write(msg);
	}

	private write(msg: DAPRequest | DAPNotification): void {
		const body = JSON.stringify(msg);
		const header = `Content-Length: ${Buffer.byteLength(body, "utf-8")}\r\n\r\n`;
		const data = header + body;

		if (this.transport === "stdio" && this.proc?.stdin?.writable) {
			this.proc.stdin.write(data, "utf-8");
		} else if (this.transport === "tcp" && this.socket?.writable) {
			this.socket.write(data, "utf-8");
		}
	}

	private handleClose(): void {
		this.closed = true;
		for (const [, pending] of this.pending) {
			pending.reject(new Error("Connection closed"));
		}
		this.pending.clear();
		this.handlers.onClose();
	}

	private parseMessages(): void {
		while (this.buffer.length > 0) {
			const headerEnd = this.buffer.indexOf("\r\n\r\n");
			if (headerEnd === -1) break;

			const header = this.buffer.substring(0, headerEnd);
			const match = header.match(/^Content-Length:\s*(\d+)/i);
			if (!match) {
				this.buffer = this.buffer.substring(headerEnd + 4);
				continue;
			}

			const contentLength = Number.parseInt(match[1], 10);
			const bodyStart = headerEnd + 4;
			const bodyEnd = bodyStart + contentLength;

			if (this.buffer.length < bodyEnd) break;

			const body = this.buffer.substring(bodyStart, bodyEnd);
			this.buffer = this.buffer.substring(bodyEnd);

			try {
				const msg = JSON.parse(body) as DAPMessage;
				this.handleMessage(msg);
			} catch {
				// Ignore malformed messages
			}
		}
	}

	private handleMessage(msg: DAPMessage): void {
		if ("id" in msg && ("result" in msg || "error" in msg)) {
			// Response
			const resp = msg as DAPResponse;
			const pending = this.pending.get(resp.id);
			if (pending) {
				this.pending.delete(resp.id);
				if ("error" in resp) {
					pending.reject(new Error(`DAP error ${resp.error.code}: ${resp.error.message}`));
				} else {
					pending.resolve(resp.result);
				}
			}
			this.handlers.onResponse(resp);
		} else if ("method" in msg) {
			// Notification / event
			const notif = msg as DAPNotification;
			this.handlers.onEvent(notif.method, notif.params ?? {});
		}
	}

	/** Kill the connection and clean up. */
	kill(): void {
		this.closed = true;
		for (const [, pending] of this.pending) {
			pending.reject(new Error("Connection killed"));
		}
		this.pending.clear();
		this.proc?.kill();
		this.proc = null;
		this.socket?.destroy();
		this.socket = null;
	}
}

/** Parse Content-Length framed messages from a raw buffer string. Returns parsed messages and remaining buffer. */
export function parseMessages(raw: string): { messages: DAPMessage[]; remaining: string } {
	const messages: DAPMessage[] = [];
	let buffer = raw;

	while (buffer.length > 0) {
		const headerEnd = buffer.indexOf("\r\n\r\n");
		if (headerEnd === -1) break;

		const header = buffer.substring(0, headerEnd);
		const match = header.match(/^Content-Length:\s*(\d+)/i);
		if (!match) {
			buffer = buffer.substring(headerEnd + 4);
			continue;
		}

		const contentLength = Number.parseInt(match[1], 10);
		const bodyStart = headerEnd + 4;
		const bodyEnd = bodyStart + contentLength;

		if (buffer.length < bodyEnd) break;

		const body = buffer.substring(bodyStart, bodyEnd);
		buffer = buffer.substring(bodyEnd);

		try {
			messages.push(JSON.parse(body) as DAPMessage);
		} catch {
			// Skip malformed
		}
	}

	return { messages, remaining: buffer };
}

import type { Connection } from "./connection.ts";
import type { DAPCapabilities, SessionState } from "../types.ts";

export interface LifecycleHandlers {
	onStateChanged: (state: SessionState) => void;
}

/**
 * Manages the DAP lifecycle handshake:
 *   initialize → launch/attach → disconnect
 *
 * State machine: initializing → launched → running → shutting_down → terminated
 */
export class Lifecycle {
	private connection: Connection;
	private capabilities: DAPCapabilities = {};
	private state: SessionState = "terminated";
	private handlers: LifecycleHandlers;
	private timeout: number;

	constructor(connection: Connection, handlers: LifecycleHandlers, timeout = 30000) {
		this.connection = connection;
		this.handlers = handlers;
		this.timeout = timeout;
	}

	getState(): SessionState {
		return this.state;
	}

	getCapabilities(): DAPCapabilities {
		return this.capabilities;
	}

	private setState(state: SessionState): void {
		this.state = state;
		this.handlers.onStateChanged(state);
	}

	/** Send DAP initialize request. */
	async initialize(clientName = "pi-debug", adapterId = "pi-debug"): Promise<DAPCapabilities> {
		this.setState("initializing");

		const result = await this.withTimeout(
			this.connection.sendRequest("initialize", {
				clientID: clientName,
				clientName,
				adapterID: adapterId,
				pathFormat: "path",
				linesStartAt1: true,
				columnsStartAt1: true,
				supportsVariableType: true,
				supportsVariablePaging: true,
				supportsRunInTerminalRequest: true,
				locale: "en-US",
			}),
			this.timeout,
		);

		this.capabilities = (result as { capabilities?: DAPCapabilities }).capabilities ?? {};
		return this.capabilities;
	}

	/** Send DAP launch request. */
	async launch(program: string, options?: {
		args?: string[];
		env?: Record<string, string>;
		stopOnEntry?: boolean;
		cwd?: string;
		runtimeArgs?: string[];
	}): Promise<void> {
		this.setState("launched");

		await this.withTimeout(
			this.connection.sendRequest("launch", {
				noDebug: false,
				program,
				args: options?.args ?? [],
				env: options?.env,
				stopOnEntry: options?.stopOnEntry ?? false,
				cwd: options?.cwd,
				runtimeArgs: options?.runtimeArgs,
			}),
			this.timeout,
		);
	}

	/** Send DAP attach request. */
	async attach(options: {
		program?: string;
		pid?: string | number;
		port?: number;
		host?: string;
	}): Promise<void> {
		this.setState("launched");

		await this.withTimeout(
			this.connection.sendRequest("attach", {
				...options,
			}),
			this.timeout,
		);
	}

	/** Send configurationDone to signal we're ready. */
	async configurationDone(): Promise<void> {
		this.setState("running");
		await this.connection.sendRequest("configurationDone");
	}

	/** Send DAP disconnect request. */
	async disconnect(terminateDebuggee = true): Promise<void> {
		this.setState("shutting_down");
		try {
			await this.connection.sendRequest("disconnect", {
				restart: false,
				terminateDebuggee,
			});
		} catch {
			// Best effort — adapter may already be gone
		}
		this.setState("terminated");
	}

	private withTimeout<T>(promise: Promise<T>, ms: number): Promise<T> {
		return new Promise<T>((resolve, reject) => {
			const timer = setTimeout(() => {
				reject(new Error(`DAP request timed out after ${ms}ms`));
			}, ms);
			promise.then(
				(value) => {
					clearTimeout(timer);
					resolve(value);
				},
				(err) => {
					clearTimeout(timer);
					reject(err);
				},
			);
		});
	}
}

import type { Connection, ConnectionEvents } from "./connection.ts";
import { Lifecycle } from "./lifecycle.ts";
import type {
	DAPCapabilities,
	SessionState,
	StoppedEvent,
	Thread,
	Source,
} from "../types.ts";

export interface SessionOptions {
	sessionId: string;
	program: string;
	args?: string[];
	env?: Record<string, string>;
	stopOnEntry?: boolean;
	cwd?: string;
	adapterId?: string;
	timeout?: number;
}

export type SessionEventHandler = (event: string, data: unknown) => void;

/**
 * Represents a single debug session.
 * Wraps Connection + Lifecycle, tracks threads and stopped state.
 */
export class Session {
	readonly sessionId: string;
	private connection: Connection;
	private lifecycle: Lifecycle;
	private threads = new Map<number, Thread>();
	private _state: SessionState = "terminated";
	private _stoppedReason: string | null = null;
	private _stoppedThreadId: number | null = null;
	private eventHandler: SessionEventHandler;

	constructor(
		sessionId: string,
		connection: Connection,
		eventHandler: SessionEventHandler,
		timeout = 30000,
	) {
		this.sessionId = sessionId;
		this.connection = connection;
		this.eventHandler = eventHandler;

		this.lifecycle = new Lifecycle(
			connection,
			{
				onStateChanged: (state) => {
					this._state = state;
				},
			},
			timeout,
		);
	}

	get state(): SessionState {
		return this._state;
	}

	get stoppedReason(): string | null {
		return this._stoppedReason;
	}

	get stoppedThreadId(): number | null {
		return this._stoppedThreadId;
	}

	get capabilities(): DAPCapabilities {
		return this.lifecycle.getCapabilities();
	}

	get isConnected(): boolean {
		return !this.connection.isClosed;
	}

	/** Send a raw DAP request through the connection. */
	sendRequest(method: string, params?: Record<string, unknown>): Promise<Record<string, unknown>> {
		return this.connection.sendRequest(method, params);
	}

	/** Send a raw DAP notification through the connection. */
	sendNotification(method: string, params?: Record<string, unknown>): void {
		this.connection.sendNotification(method, params);
	}

	/** Initialize and launch the debug session. */
	async start(options: Omit<SessionOptions, "sessionId">): Promise<DAPCapabilities> {
		const caps = await this.lifecycle.initialize("pi-debug", options.adapterId ?? "pi-debug");
		await this.lifecycle.launch(options.program, {
			args: options.args,
			env: options.env,
			stopOnEntry: options.stopOnEntry,
			cwd: options.cwd,
		});
		await this.lifecycle.configurationDone();
		return caps;
	}

	/** Attach to a running process. */
	async attach(options: {
		program?: string;
		pid?: string | number;
		port?: number;
		host?: string;
		adapterId?: string;
	}): Promise<DAPCapabilities> {
		const caps = await this.lifecycle.initialize("pi-debug", options.adapterId ?? "pi-debug");
		await this.lifecycle.attach({
			program: options.program,
			pid: options.pid,
			port: options.port,
			host: options.host,
		});
		await this.lifecycle.configurationDone();
		return caps;
	}

	/** Stop the debug session. */
	async stop(): Promise<void> {
		await this.lifecycle.disconnect(true);
		this.connection.kill();
	}

	/** Handle a DAP event from the connection. */
	handleEvent(method: string, params: Record<string, unknown>): void {
		switch (method) {
			case "stopped": {
				const stopped = params as unknown as StoppedEvent;
				this._state = "stopped";
				this._stoppedReason = stopped.reason;
				this._stoppedThreadId = stopped.threadId ?? null;
				break;
			}
			case "continued": {
				this._state = "running";
				this._stoppedReason = null;
				this._stoppedThreadId = null;
				break;
			}
			case "terminated": {
				this._state = "terminated";
				break;
			}
			case "thread": {
				const threadData = params as { reason: string; threadId: number };
				if (threadData.reason === "started") {
					this.threads.set(threadData.threadId, {
						id: threadData.threadId,
						name: `Thread ${threadData.threadId}`,
					});
				} else {
					this.threads.delete(threadData.threadId);
				}
				break;
			}
		}
		this.eventHandler(method, params);
	}

	/** Get a thread ID for stepping. Falls back to first known thread or 1. */
	getDefaultThreadId(): number {
		if (this._stoppedThreadId !== null) return this._stoppedThreadId;
		const first = this.threads.keys().next();
		if (!first.done) return first.value;
		return 1;
	}
}

import { Connection, type ConnectionEvents } from "./connection.ts";
import { Session, type SessionEventHandler } from "./session.ts";
import type { SessionOptions, DAPCapabilities } from "../types.ts";

let sessionCounter = 0;

/**
 * Manages multiple debug sessions.
 * Tracks an "active" session that tools operate on by default.
 */
export class DebugSessionManager {
	private sessions = new Map<string, Session>();
	private _activeSessionId: string | null = null;
	private eventHandler: SessionEventHandler;
	private cwd: string;

	constructor(cwd: string, eventHandler?: SessionEventHandler) {
		this.cwd = cwd;
		this.eventHandler = eventHandler ?? (() => {});
	}

	get activeSessionId(): string | null {
		return this._activeSessionId;
	}

	get sessionCount(): number {
		return this.sessions.size;
	}

	/** Get the active session, or throw if none. */
	getActiveSession(): Session {
		if (!this._activeSessionId) {
			throw new Error("No active debug session. Use debug_start first.");
		}
		const session = this.sessions.get(this._activeSessionId);
		if (!session) {
			throw new Error(`Active session ${this._activeSessionId} not found.`);
		}
		return session;
	}

	/** Get a session by ID. */
	getSession(sessionId: string): Session | undefined {
		return this.sessions.get(sessionId);
	}

	/**
	 * Create and start a new debug session.
	 * Spawns the adapter process and runs initialize → launch → configurationDone.
	 */
	async startSession(options: Omit<SessionOptions, "sessionId">): Promise<{ sessionId: string; capabilities: DAPCapabilities }> {
		const sessionId = `debug_${++sessionCounter}_${Date.now()}`;

		const connection = new Connection({
			onResponse: () => {},
			onEvent: (method, params) => {
				session.handleEvent(method, params);
			},
			onError: (error) => {
				this.eventHandler("connection_error", { sessionId, error: error.message });
			},
			onClose: () => {
				this.eventHandler("connection_close", { sessionId });
			},
		} satisfies ConnectionEvents);

		const session = new Session(
			sessionId,
			connection,
			this.eventHandler,
			options.timeout,
		);

		// Start the adapter process (stdio transport)
		// The adapter command should be resolved externally before calling this
		// For now, assume the caller has already set up the transport
		this.sessions.set(sessionId, session);
		this._activeSessionId = sessionId;

		return { sessionId, capabilities: {} };
	}

	/** Register a session that was set up externally (e.g. with transport already connected). */
	registerSession(session: Session): void {
		this.sessions.set(session.sessionId, session);
		this._activeSessionId = session.sessionId;
	}

	/** Stop a specific session. */
	async stopSession(sessionId: string): Promise<void> {
		const session = this.sessions.get(sessionId);
		if (!session) return;

		try {
			await session.stop();
		} catch {
			// Best effort
		}

		this.sessions.delete(sessionId);
		if (this._activeSessionId === sessionId) {
			// Fall back to another session or null
			const remaining = this.sessions.keys().next();
			this._activeSessionId = remaining.done ? null : remaining.value;
		}
	}

	/** Stop the active session. */
	async stopActiveSession(): Promise<void> {
		if (this._activeSessionId) {
			await this.stopSession(this._activeSessionId);
		}
	}

	/** Stop all sessions. */
	async stopAll(): Promise<void> {
		const ids = [...this.sessions.keys()];
		await Promise.all(ids.map((id) => this.stopSession(id)));
	}

	/** Set a specific session as active. */
	setActive(sessionId: string): void {
		if (!this.sessions.has(sessionId)) {
			throw new Error(`Session ${sessionId} not found.`);
		}
		this._activeSessionId = sessionId;
	}

	/** List all session IDs. */
	listSessions(): string[] {
		return [...this.sessions.keys()];
	}
}

import type { Session, Breakpoint, Source } from "../client/session.ts";
import type { DAPBreakpoint as DAPBreakpointType } from "../types.ts";

export interface SetBreakpointsParams {
	file: string;
	breakpoints: Array<{
		line: number;
		column?: number;
		condition?: string;
		hitCount?: number;
		logMessage?: string;
	}>;
}

export interface SetBreakpointsResult {
	breakpoints: BreakpointResult[];
}

export interface BreakpointResult {
	id?: number;
	verified: boolean;
	line?: number;
	column?: number;
	message?: string;
}

/**
 * Set source breakpoints in a file.
 * DAP replaces all breakpoints for a source in a single call.
 */
export async function setBreakpoints(
	session: Session,
	params: SetBreakpointsParams,
): Promise<SetBreakpointsResult> {
	const source: Source = { path: params.file };

	const bpParams = params.breakpoints.map((bp) => {
		const entry: Record<string, unknown> = { line: bp.line };
		if (bp.column !== undefined) entry.column = bp.column;
		if (bp.condition) entry.condition = bp.condition;
		if (bp.hitCount !== undefined) entry.hitCondition = String(bp.hitCount);
		if (bp.logMessage) entry.logMessage = bp.logMessage;
		return entry;
	});

	const result = await session.sendRequest("setBreakpoints", {
		source,
		breakpoints: bpParams,
		lines: params.breakpoints.map((bp) => bp.line),
	});

	const breakpoints = (result.breakpoints ?? []) as BreakpointResult[];
	return { breakpoints };
}

/**
 * Remove all breakpoints for a file by setting an empty list.
 */
export async function clearBreakpoints(
	session: Session,
	file: string,
): Promise<void> {
	await session.sendRequest("setBreakpoints", {
		source: { path: file },
		breakpoints: [],
		lines: [],
	});
}

/**
 * Set exception breakpoints (break on caught/uncaught exceptions).
 */
export async function setExceptionBreakpoints(
	session: Session,
	filters: Array<{ filter: string; condition?: string }>,
): Promise<void> {
	await session.sendRequest("setExceptionBreakpoints", {
		filters: filters.map((f) => f.filter),
		filterOptions: filters.map((f) => ({
			filterId: f.filter,
			condition: f.condition,
		})),
	});
}

import type { Session } from "../client/session.ts";
import type { StackFrame } from "../types.ts";

export interface StackTraceParams {
	threadId?: number;
	startFrame?: number;
	levels?: number;
}

export interface StackTraceResult {
	stackFrames: StackFrameInfo[];
	totalFrames?: number;
}

export interface StackFrameInfo {
	id: number;
	name: string;
	file?: string;
	line: number;
	column: number;
	source?: { name?: string; path?: string };
}

/**
 * Request a stack trace from the debug session.
 */
export async function stackTrace(
	session: Session,
	params: StackTraceParams = {},
): Promise<StackTraceResult> {
	const threadId = params.threadId ?? session.getDefaultThreadId();

	const result = await session.sendRequest("stackTrace", {
		threadId,
		startFrame: params.startFrame ?? 0,
		levels: params.levels ?? 50,
	});

	const frames = (result.stackFrames ?? []) as StackFrame[];
	const stackFrames: StackFrameInfo[] = frames.map((f) => ({
		id: f.id,
		name: f.name,
		file: f.source?.path,
		line: f.line,
		column: f.column,
		source: f.source ? { name: f.source.name, path: f.source.path } : undefined,
	}));

	return {
		stackFrames,
		totalFrames: (result.totalFrames as number | undefined),
	};
}

import type { Session } from "../client/session.ts";
import type { Scope, Variable } from "../types.ts";

export interface VariablesParams {
	frameIndex?: number;
	scope?: "locals" | "globals" | "watch";
}

export interface ScopesResult {
	scopes: ScopeInfo[];
}

export interface ScopeInfo {
	name: string;
	variablesReference: number;
	namedVariables?: number;
	indexedVariables?: number;
	expensive: boolean;
}

export interface VariablesResult {
	variables: VariableInfo[];
}

export interface VariableInfo {
	name: string;
	value: string;
	type?: string;
	variablesReference: number;
	evaluateName?: string;
}

/**
 * Get scopes for a stack frame.
 */
export async function scopes(
	session: Session,
	frameId: number,
): Promise<ScopesResult> {
	const result = await session.sendRequest("scopes", { frameId });
	const scopeList = (result.scopes ?? []) as Scope[];
	return {
		scopes: scopeList.map((s) => ({
			name: s.name,
			variablesReference: s.variablesReference,
			namedVariables: s.namedVariables,
			indexedVariables: s.indexedVariables,
			expensive: s.expensive,
		})),
	};
}

/**
 * Get variables for a scope or variable reference.
 */
export async function variables(
	session: Session,
	variablesReference: number,
): Promise<VariablesResult> {
	const result = await session.sendRequest("variables", { variablesReference });
	const vars = (result.variables ?? []) as Variable[];
	return {
		variables: vars.map((v) => ({
			name: v.name,
			value: v.value,
			type: v.type,
			variablesReference: v.variablesReference,
			evaluateName: v.evaluateName,
		})),
	};
}

/**
 * Get all variables for the top stack frame, optionally filtered by scope name.
 */
export async function frameVariables(
	session: Session,
	frameId: number,
	scopeFilter?: "locals" | "globals" | "watch",
): Promise<Array<{ scope: string; variables: VariableInfo[] }>> {
	const scopesResult = await scopes(session, frameId);

	const results: Array<{ scope: string; variables: VariableInfo[] }> = [];
	for (const scope of scopesResult.scopes) {
		if (scopeFilter) {
			const nameLower = scope.name.toLowerCase();
			const matches =
				(scopeFilter === "locals" && (nameLower.includes("local") || nameLower === "局部")) ||
				(scopeFilter === "globals" && nameLower.includes("global")) ||
				(scopeFilter === "watch" && nameLower.includes("watch"));
			if (!matches) continue;
		}

		if (scope.variablesReference > 0) {
			const vars = await variables(session, scope.variablesReference);
			results.push({ scope: scope.name, variables: vars.variables });
		}
	}

	return results;
}

import type { Session } from "../client/session.ts";

export type StepAction = "continue" | "stepOver" | "stepInto" | "stepOut" | "pause";

export interface StepParams {
	action: StepAction;
	threadId?: number;
}

export interface StepResult {
	success: boolean;
	message?: string;
}

/** Map step actions to DAP request methods. */
const ACTION_METHOD_MAP: Record<StepAction, string> = {
	continue: "continue",
	stepOver: "next",
	stepInto: "stepIn",
	stepOut: "stepOut",
	pause: "pause",
};

/**
 * Execute a step action (continue, stepOver, stepInto, stepOut, pause).
 */
export async function stepping(
	session: Session,
	params: StepParams,
): Promise<StepResult> {
	const method = ACTION_METHOD_MAP[params.action];
	if (!method) {
		return { success: false, message: `Unknown step action: ${params.action}` };
	}

	const threadId = params.threadId ?? session.getDefaultThreadId();

	try {
		await session.sendRequest(method, { threadId });
		return { success: true };
	} catch (error) {
		return {
			success: false,
			message: error instanceof Error ? error.message : String(error),
		};
	}
}

import type { Session } from "../client/session.ts";

export interface EvaluateParams {
	expression: string;
	frameId?: number;
	context?: "repl" | "watch" | "hover" | "clipboard";
}

export interface EvaluateResult {
	result: string;
	type?: string;
	variablesReference: number;
}

/**
 * Evaluate an expression in the debug context.
 */
export async function evaluate(
	session: Session,
	params: EvaluateParams,
): Promise<EvaluateResult> {
	const requestParams: Record<string, unknown> = {
		expression: params.expression,
		context: params.context ?? "repl",
	};

	if (params.frameId !== undefined) {
		requestParams.frameId = params.frameId;
	}

	const result = await session.sendRequest("evaluate", requestParams);

	return {
		result: (result.result as string) ?? "",
		type: result.type as string | undefined,
		variablesReference: (result.variablesReference as number) ?? 0,
	};
}

