import type { AdapterConfig } from "../types.ts";

/**
 * Load and validate user-configured adapters from .pi/pi-debug.json config.
 */
export function loadCustomAdapters(
	configured: Record<string, Partial<AdapterConfig> & { enabled?: boolean }>,
): AdapterConfig[] {
	const adapters: AdapterConfig[] = [];

	for (const [name, config] of Object.entries(configured)) {
		if (config.enabled === false) continue;
		if (!config.command || !config.extensions || config.extensions.length === 0) {
			continue;
		}

		adapters.push({
			language: config.language ?? name,
			command: config.command,
			adapter: config.adapter ?? name,
			extensions: config.extensions,
			detectionFiles: config.detectionFiles ?? [],
			transport: config.transport ?? "stdio",
			port: config.port,
			host: config.host,
		});
	}

	return adapters;
}

import { existsSync } from "node:fs";
import { extname, resolve } from "node:path";
import type { AdapterConfig } from "../types.ts";
import { getBuiltinAdapters } from "./index.ts";
import { loadCustomAdapters } from "./custom.ts";

/**
 * AdapterRegistry resolves file paths to appropriate debug adapter configurations.
 * Built-in adapters can be overridden by user-configured adapters.
 */
export class AdapterRegistry {
	private adapters: AdapterConfig[] = [];
	private customAdapters: AdapterConfig[] = [];

	constructor(customConfig?: Record<string, Partial<AdapterConfig> & { enabled?: boolean }>) {
		this.adapters = getBuiltinAdapters();
		if (customConfig) {
			this.customAdapters = loadCustomAdapters(customConfig);
		}
	}

	/** Resolve an adapter for a file path based on extension. */
	resolve(filePath: string, cwd?: string): AdapterConfig | undefined {
		const ext = extname(filePath);

		// Custom adapters take priority
		const custom = this.customAdapters.find((a) =>
			a.extensions.includes(ext),
		);
		if (custom) return custom;

		// Built-in adapters
		const builtin = this.adapters.find((a) =>
			a.extensions.includes(ext),
		);
		if (builtin) return builtin;

		return undefined;
	}

	/** Resolve adapter by name. */
	getByName(name: string): AdapterConfig | undefined {
		return (
			this.customAdapters.find((a) => a.adapter === name || a.language === name) ??
			this.adapters.find((a) => a.adapter === name || a.language === name)
		);
	}

	/** Check if a detection file exists in the cwd, indicating this adapter type is relevant. */
	async detect(cwd: string): Promise<AdapterConfig[]> {
		const detected: AdapterConfig[] = [];
		const all = [...this.customAdapters, ...this.adapters];

		for (const adapter of all) {
			if (adapter.detectionFiles.length === 0) {
				detected.push(adapter);
				continue;
			}
			for (const detectionFile of adapter.detectionFiles) {
				if (existsSync(resolve(cwd, detectionFile))) {
					detected.push(adapter);
					break;
				}
			}
		}

		return detected;
	}

	/** Get all registered adapters. */
	getAll(): AdapterConfig[] {
		return [...this.customAdapters, ...this.adapters];
	}
}

import type { ExtensionAPI, ExtensionContext } from "@mariozechner/pi-coding-agent";
import { loadConfig } from "../config.ts";
import { DebugSessionManager } from "../client/manager.ts";
import { registerDebugTools } from "./tool-registry.ts";
import type { Session } from "../client/session.ts";
import { Connection, type ConnectionEvents } from "../client/connection.ts";
import type { AdapterConfig } from "../types.ts";
import { AdapterRegistry } from "../adapters/registry.ts";

export function registerPiDebug(pi: ExtensionAPI): void {
	let manager: DebugSessionManager | undefined;
	let registry: AdapterRegistry | undefined;
	let currentCtx: ExtensionContext | undefined;

	pi.on("session_start", (_event, ctx) => {
		currentCtx = ctx;
		const { config } = loadConfig(ctx.cwd);

		if (!config.enabled) return;

		manager = new DebugSessionManager(ctx.cwd);
		registry = new AdapterRegistry(config.adapters);

		registerDebugTools(pi, manager, registry, config);
	});

	pi.on("session_shutdown", async () => {
		if (manager) {
			await manager.stopAll();
			manager = undefined;
		}
		registry = undefined;
		currentCtx = undefined;
	});
}

/**
 * Helper: spawn a debug adapter and create a fully wired Session.
 */
export async function spawnSession(
	manager: DebugSessionManager,
	adapter: AdapterConfig,
	program: string,
	options: {
		args?: string[];
		env?: Record<string, string>;
		stopOnEntry?: boolean;
		cwd?: string;
		timeout?: number;
	},
): Promise<Session> {
	const connection = new Connection({
		onResponse: () => {},
		onEvent: (method, params) => {
			session.handleEvent(method, params);
		},
		onError: (error) => {
			void error;
		},
		onClose: () => {},
	} satisfies ConnectionEvents);

	const sessionId = `debug_${Date.now()}`;
	const session = new Session(
		sessionId,
		connection,
		() => {},
		options.timeout,
	);

	// Start transport
	if (adapter.transport === "stdio") {
		connection.startStdio(adapter.command, options.cwd ?? process.cwd(), options.env);
	} else if (adapter.transport === "tcp") {
		const port = adapter.port ?? 0;
		const host = adapter.host ?? "127.0.0.1";
		await connection.connectTcp(host, port);
	}

	// Initialize DAP handshake
	await session.start({
		program,
		args: options.args,
		env: options.env,
		stopOnEntry: options.stopOnEntry,
		cwd: options.cwd,
		adapterId: adapter.adapter,
		timeout: options.timeout,
	});

	manager.registerSession(session);
	return session;
}

import type { ExtensionAPI, ToolDefinition } from "@mariozechner/pi-coding-agent";
import { Type } from "typebox";
import type { DebugSessionManager } from "../client/manager.ts";
import type { AdapterRegistry } from "../adapters/registry.ts";
import type { PiDebugConfig } from "../types.ts";
import { setBreakpoints, clearBreakpoints } from "../features/breakpoints.ts";
import { stackTrace } from "../features/stacktrace.ts";
import { frameVariables } from "../features/variables.ts";
import { stepping } from "../features/stepping.ts";
import { evaluate } from "../features/evaluate.ts";

interface DebugToolDetails {
	tool: string;
	status: "ok" | "error";
}

function debugResult(text: string, isError = false): { content: Array<{ type: "text"; text: string }>; details: DebugToolDetails; isError?: boolean } {
	return {
		content: [{ type: "text", text }],
		details: { tool: "debug", status: isError ? "error" : "ok" },
		...(isError ? { isError: true as const } : {}),
	};
}

export function registerDebugTools(
	pi: ExtensionAPI,
	manager: DebugSessionManager,
	registry: AdapterRegistry,
	config: PiDebugConfig,
): void {
	// debug_start
	pi.registerTool({
		name: "debug_start",
		label: "Debug: Start Session",
		description: "Start a debug session for a program. Spawns the appropriate debug adapter and begins execution.",
		parameters: Type.Object({
			program: Type.String({ description: "File to debug." }),
			args: Type.Optional(Type.Array(Type.String(), { description: "Program arguments." })),
			adapter: Type.Optional(Type.String({ description: 'Adapter name: "node", "python", or custom. Default: auto-detect.' })),
			stopOnEntry: Type.Optional(Type.Boolean({ description: "Stop on entry. Default: true." })),
			env: Type.Optional(Type.Record(Type.String(), Type.String(), { description: "Environment variables." })),
		}) as never,
		async execute(_id, params) {
			const p = params as { program: string; args?: string[]; adapter?: string; stopOnEntry?: boolean; env?: Record<string, string> };
			try {
				let adapterConfig = p.adapter
					? registry.getByName(p.adapter)
					: registry.resolve(p.program);

				if (!adapterConfig) {
					return debugResult(`No debug adapter found for ${p.program}. Specify an adapter explicitly.`, true);
				}

				const connection = await import("node:child_process").then(() => {
					// Dynamic import only for the Connection wiring below
					return null;
				}).catch(() => null);

				// Create a simple session through the manager
				const { sessionId } = await manager.startSession({
					program: p.program,
					args: p.args,
					env: p.env,
					stopOnEntry: p.stopOnEntry ?? config.stopOnEntry,
					timeout: config.timeout,
				});

				return debugResult(`Debug session ${sessionId} created. Adapter: ${adapterConfig.adapter} (${adapterConfig.transport}). Program: ${p.program}`);
			} catch (error) {
				return debugResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// debug_stop
	pi.registerTool({
		name: "debug_stop",
		label: "Debug: Stop Session",
		description: "Stop the active debug session and disconnect from the debug adapter.",
		parameters: Type.Object({}) as never,
		async execute() {
			try {
				await manager.stopActiveSession();
				return debugResult("Debug session stopped.");
			} catch (error) {
				return debugResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// debug_breakpoint
	pi.registerTool({
		name: "debug_breakpoint",
		label: "Debug: Set Breakpoint",
		description: "Set a breakpoint in a file at a specific line. Supports conditions and hit counts.",
		parameters: Type.Object({
			file: Type.String({ description: "File path." }),
			line: Type.Number({ description: "Line number (1-based)." }),
			condition: Type.Optional(Type.String({ description: 'Conditional expression, e.g. "x > 10".' })),
			hitCount: Type.Optional(Type.Number({ description: "Break after N hits." })),
			remove: Type.Optional(Type.Boolean({ description: "Remove breakpoints for this file instead of setting." })),
		}) as never,
		async execute(_id, params) {
			const p = params as { file: string; line: number; condition?: string; hitCount?: number; remove?: boolean };
			try {
				const session = manager.getActiveSession();
				if (p.remove) {
					await clearBreakpoints(session, p.file);
					return debugResult(`Breakpoints cleared for ${p.file}`);
				}
				const result = await setBreakpoints(session, {
					file: p.file,
					breakpoints: [{
						line: p.line,
						condition: p.condition,
						hitCount: p.hitCount,
					}],
				});
				const bp = result.breakpoints[0];
				return debugResult(`Breakpoint set: ${p.file}:${p.line} (verified: ${bp?.verified ?? false}${bp?.message ? `, ${bp.message}` : ""})`);
			} catch (error) {
				return debugResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// debug_continue
	pi.registerTool({
		name: "debug_continue",
		label: "Debug: Continue/Step",
		description: 'Continue execution or step through code. Actions: continue, stepOver, stepInto, stepOut.',
		parameters: Type.Object({
			action: Type.Union([
				Type.Literal("continue"),
				Type.Literal("stepOver"),
				Type.Literal("stepInto"),
				Type.Literal("stepOut"),
			], { description: "Step action." }),
		}) as never,
		async execute(_id, params) {
			const p = params as { action: "continue" | "stepOver" | "stepInto" | "stepOut" };
			try {
				const session = manager.getActiveSession();
				const result = await stepping(session, { action: p.action });
				if (result.success) {
					return debugResult(`${p.action}: OK`);
				}
				return debugResult(`${p.action} failed: ${result.message}`, true);
			} catch (error) {
				return debugResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// debug_stack
	pi.registerTool({
		name: "debug_stack",
		label: "Debug: Stack Trace",
		description: "Get the current stack trace.",
		parameters: Type.Object({
			levels: Type.Optional(Type.Number({ description: "Max frames to return. Default: 50." })),
		}) as never,
		async execute(_id, params) {
			const p = params as { levels?: number };
			try {
				const session = manager.getActiveSession();
				const result = await stackTrace(session, { levels: p.levels ?? config.maxStackFrames });
				const formatted = result.stackFrames
					.map((f, i) => `  #${i} ${f.name} at ${f.file ?? "?"}:${f.line}:${f.column}`)
					.join("\n");
				return debugResult(`Stack trace (${result.stackFrames.length} frames${result.totalFrames ? ` of ${result.totalFrames}` : ""}):\n${formatted}`);
			} catch (error) {
				return debugResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// debug_variables
	pi.registerTool({
		name: "debug_variables",
		label: "Debug: Variables",
		description: "Inspect variables in the current stack frame. Optionally filter by scope.",
		parameters: Type.Object({
			scope: Type.Optional(Type.Union([
				Type.Literal("locals"),
				Type.Literal("globals"),
				Type.Literal("watch"),
			], { description: "Filter by scope. Default: all scopes." })),
			frameIndex: Type.Optional(Type.Number({ description: "Stack frame index. Default: 0 (top frame)." })),
		}) as never,
		async execute(_id, params) {
			const p = params as { scope?: "locals" | "globals" | "watch"; frameIndex?: number };
			try {
				const session = manager.getActiveSession();
				// Get frame ID from stack trace
				const stack = await stackTrace(session, { levels: 1 });
				if (stack.stackFrames.length === 0) {
					return debugResult("No stack frames available.");
				}
				const frameIndex = p.frameIndex ?? 0;
				const frameId = stack.stackFrames[frameIndex]?.id ?? stack.stackFrames[0].id;

				const result = await frameVariables(session, frameId, p.scope);
				const lines: string[] = [];
				for (const scopeResult of result) {
					lines.push(`[${scopeResult.scope}]`);
					for (const v of scopeResult.variables) {
						lines.push(`  ${v.name}: ${v.value}${v.type ? ` (${v.type})` : ""}`);
					}
				}
				return debugResult(lines.length > 0 ? lines.join("\n") : "No variables found.");
			} catch (error) {
				return debugResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// debug_evaluate
	pi.registerTool({
		name: "debug_evaluate",
		label: "Debug: Evaluate Expression",
		description: "Evaluate an expression in the current debug context.",
		parameters: Type.Object({
			expression: Type.String({ description: "Expression to evaluate." }),
			frameIndex: Type.Optional(Type.Number({ description: "Stack frame index. Default: 0." })),
			context: Type.Optional(Type.Union([
				Type.Literal("repl"),
				Type.Literal("watch"),
				Type.Literal("hover"),
			], { description: "Evaluation context. Default: repl." })),
		}) as never,
		async execute(_id, params) {
			const p = params as { expression: string; frameIndex?: number; context?: "repl" | "watch" | "hover" };
			try {
				const session = manager.getActiveSession();
				let frameId: number | undefined;
				if (p.frameIndex !== undefined) {
					const stack = await stackTrace(session, { startFrame: p.frameIndex, levels: 1 });
					frameId = stack.stackFrames[0]?.id;
				}
				const result = await evaluate(session, {
					expression: p.expression,
					frameId,
					context: p.context,
				});
				return debugResult(`${p.expression} = ${result.result}${result.type ? ` (${result.type})` : ""}`);
			} catch (error) {
				return debugResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);
}

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { Connection, parseMessages } from "../../src/client/connection.ts";

describe("Connection", () => {
	it("starts in non-closed state", () => {
		const conn = new Connection({
			onResponse: () => {},
			onEvent: () => {},
			onError: () => {},
			onClose: () => {},
		});
		assert.equal(conn.isClosed, false);
	});

	it("sendRequest rejects when closed", async () => {
		const conn = new Connection({
			onResponse: () => {},
			onEvent: () => {},
			onError: () => {},
			onClose: () => {},
		});
		conn.kill();
		await assert.rejects(
			() => conn.sendRequest("test"),
			/Connection is closed/,
		);
	});

	it("sendNotification does not throw when closed", () => {
		const conn = new Connection({
			onResponse: () => {},
			onEvent: () => {},
			onError: () => {},
			onClose: () => {},
		});
		conn.kill();
		// Should not throw
		conn.sendNotification("test", {});
	});

	it("kill closes the connection", () => {
		const conn = new Connection({
			onResponse: () => {},
			onEvent: () => {},
			onError: () => {},
			onClose: () => {},
		});
		conn.kill();
		assert.equal(conn.isClosed, true);
	});
});

describe("parseMessages", () => {
	it("parses a single well-framed message", () => {
		const body = JSON.stringify({ jsonrpc: "2.0", id: 1, result: { body: {} } });
		const framed = `Content-Length: ${Buffer.byteLength(body)}\r\n\r\n${body}`;
		const { messages, remaining } = parseMessages(framed);
		assert.equal(messages.length, 1);
		assert.equal((messages[0] as { id: number }).id, 1);
		assert.equal(remaining, "");
	});

	it("parses multiple messages", () => {
		const body1 = JSON.stringify({ jsonrpc: "2.0", id: 1, result: {} });
		const body2 = JSON.stringify({ jsonrpc: "2.0", method: "stopped", params: { reason: "breakpoint" } });
		const framed =
			`Content-Length: ${Buffer.byteLength(body1)}\r\n\r\n${body1}` +
			`Content-Length: ${Buffer.byteLength(body2)}\r\n\r\n${body2}`;
		const { messages } = parseMessages(framed);
		assert.equal(messages.length, 2);
	});

	it("returns remaining partial data", () => {
		const body = JSON.stringify({ jsonrpc: "2.0", id: 1, result: {} });
		const partial = `Content-Length: 999\r\n\r\n${body}`;
		const { messages, remaining } = parseMessages(partial);
		assert.equal(messages.length, 0);
		assert.ok(remaining.length > 0);
	});

	it("skips messages with invalid Content-Length header", () => {
		const body = JSON.stringify({ jsonrpc: "2.0", id: 1, result: {} });
		const framed = `BadHeader: true\r\n\r\n${body}`;
		const { messages, remaining } = parseMessages(framed);
		assert.equal(messages.length, 0);
		assert.equal(remaining, body);
	});

	it("handles empty input", () => {
		const { messages, remaining } = parseMessages("");
		assert.equal(messages.length, 0);
		assert.equal(remaining, "");
	});

	it("parses event notifications", () => {
		const body = JSON.stringify({ jsonrpc: "2.0", method: "stopped", params: { reason: "breakpoint" } });
		const framed = `Content-Length: ${Buffer.byteLength(body)}\r\n\r\n${body}`;
		const { messages } = parseMessages(framed);
		assert.equal(messages.length, 1);
		assert.equal("method" in messages[0] && messages[0].method, "stopped");
	});
});

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { Lifecycle } from "../../src/client/lifecycle.ts";
import type { Connection } from "../../src/client/connection.ts";

/** Create a mock connection that records sent requests and responds programmatically. */
function createMockConnection(responses: Map<string, Record<string, unknown>>): Connection {
	const stateChanges: string[] = [];
	return {
		isClosed: false,
		transportType: "stdio" as const,
		async sendRequest(method: string, _params?: Record<string, unknown>): Promise<Record<string, unknown>> {
			const resp = responses.get(method);
			if (resp) return resp;
			return {};
		},
		sendNotification(_method: string, _params?: Record<string, unknown>): void {},
		kill(): void {},
		startStdio(): void {},
		connectTcp(): Promise<void> { return Promise.resolve(); },
	} as unknown as Connection;
}

describe("Lifecycle", () => {
	it("starts in terminated state", () => {
		const states: string[] = [];
		const conn = createMockConnection(new Map());
		const lifecycle = new Lifecycle(conn, {
			onStateChanged: (state) => states.push(state),
		});
		assert.equal(lifecycle.getState(), "terminated");
	});

	it("transitions to initializing after initialize", async () => {
		const states: string[] = [];
		const responses = new Map<string, Record<string, unknown>>();
		responses.set("initialize", {
			capabilities: { supportsConditionalBreakpoints: true },
		});

		const conn = createMockConnection(responses);
		const lifecycle = new Lifecycle(conn, {
			onStateChanged: (state) => states.push(state),
		}, 5000);

		const caps = await lifecycle.initialize();
		assert.equal(lifecycle.getState(), "initializing");
		assert.equal(caps.supportsConditionalBreakpoints, true);
		assert.deepEqual(states, ["initializing"]);
	});

	it("transitions to launched after launch", async () => {
		const states: string[] = [];
		const responses = new Map<string, Record<string, unknown>>();
		responses.set("launch", {});

		const conn = createMockConnection(responses);
		const lifecycle = new Lifecycle(conn, {
			onStateChanged: (state) => states.push(state),
		}, 5000);

		await lifecycle.launch("test.js");
		assert.equal(lifecycle.getState(), "launched");
	});

	it("transitions to running after configurationDone", async () => {
		const states: string[] = [];
		const responses = new Map<string, Record<string, unknown>>();
		responses.set("configurationDone", {});

		const conn = createMockConnection(responses);
		const lifecycle = new Lifecycle(conn, {
			onStateChanged: (state) => states.push(state),
		}, 5000);

		await lifecycle.configurationDone();
		assert.equal(lifecycle.getState(), "running");
	});

	it("transitions to terminated after disconnect", async () => {
		const states: string[] = [];
		const responses = new Map<string, Record<string, unknown>>();
		responses.set("disconnect", {});

		const conn = createMockConnection(responses);
		const lifecycle = new Lifecycle(conn, {
			onStateChanged: (state) => states.push(state),
		}, 5000);

		await lifecycle.disconnect();
		assert.equal(lifecycle.getState(), "terminated");
	});

	it("parses capabilities from initialize response", async () => {
		const responses = new Map<string, Record<string, unknown>>();
		responses.set("initialize", {
			capabilities: {
				supportsConditionalBreakpoints: true,
				supportsHitConditionalBreakpoints: false,
				supportsStepBack: true,
			},
		});

		const conn = createMockConnection(responses);
		const lifecycle = new Lifecycle(conn, {
			onStateChanged: () => {},
		}, 5000);

		await lifecycle.initialize();
		const caps = lifecycle.getCapabilities();
		assert.equal(caps.supportsConditionalBreakpoints, true);
		assert.equal(caps.supportsHitConditionalBreakpoints, false);
		assert.equal(caps.supportsStepBack, true);
	});
});

