function createMockConnection(requestHandler?: (method: string, params?: Record<string, unknown>) => Record<string, unknown>): Connection {
	return {
		isClosed: false,
		transportType: "stdio" as const,
		async sendRequest(method: string, params?: Record<string, unknown>): Promise<Record<string, unknown>> {
			if (requestHandler) return requestHandler(method, params);
			return {};
		},
		sendNotification(): void {},
		kill(): void {},
		startStdio(): void {},
		connectTcp(): Promise<void> { return Promise.resolve(); },
	} as unknown as Connection;
}

describe("Session", () => {
	it("starts in terminated state", () => {
		const conn = createMockConnection();
		const session = new Session("test-1", conn, () => {});
		assert.equal(session.state, "terminated");
		assert.equal(session.sessionId, "test-1");
	});

	it("handles stopped event", () => {
		const conn = createMockConnection();
		const session = new Session("test-1", conn, () => {});
		session.handleEvent("stopped", {
			reason: "breakpoint",
			threadId: 1,
		});
		assert.equal(session.state, "stopped");
		assert.equal(session.stoppedReason, "breakpoint");
		assert.equal(session.stoppedThreadId, 1);
	});

	it("handles continued event", () => {
		const conn = createMockConnection();
		const session = new Session("test-1", conn, () => {});
		// First stop
		session.handleEvent("stopped", { reason: "breakpoint", threadId: 1 });
		assert.equal(session.state, "stopped");
		// Then continue
		session.handleEvent("continued", { threadId: 1 });
		assert.equal(session.state, "running");
		assert.equal(session.stoppedReason, null);
		assert.equal(session.stoppedThreadId, null);
	});

	it("handles terminated event", () => {
		const conn = createMockConnection();
		const session = new Session("test-1", conn, () => {});
		session.handleEvent("terminated", {});
		assert.equal(session.state, "terminated");
	});

	it("tracks threads", () => {
		const conn = createMockConnection();
		const session = new Session("test-1", conn, () => {});
		session.handleEvent("thread", { reason: "started", threadId: 1 });
		session.handleEvent("thread", { reason: "started", threadId: 2 });
		assert.equal(session.getDefaultThreadId(), 1);
	});

	it("removes threads on exit", () => {
		const conn = createMockConnection();
		const session = new Session("test-1", conn, () => {});
		session.handleEvent("thread", { reason: "started", threadId: 1 });
		session.handleEvent("thread", { reason: "exited", threadId: 1 });
		// No threads remain, should default to 1
		assert.equal(session.getDefaultThreadId(), 1);
	});

	it("getDefaultThreadId returns stopped thread id", () => {
		const conn = createMockConnection();
		const session = new Session("test-1", conn, () => {});
		session.handleEvent("thread", { reason: "started", threadId: 1 });
		session.handleEvent("thread", { reason: "started", threadId: 2 });
		session.handleEvent("stopped", { reason: "breakpoint", threadId: 2 });
		assert.equal(session.getDefaultThreadId(), 2);
	});

	it("forwards events to handler", () => {
		const events: Array<{ method: string; data: unknown }> = [];
		const conn = createMockConnection();
		const session = new Session("test-1", conn, (method, data) => {
			events.push({ method, data });
		});
		session.handleEvent("output", { output: "hello" });
		assert.equal(events.length, 1);
		assert.equal(events[0].method, "output");
	});

	it("delegates sendRequest to connection", async () => {
		const conn = createMockConnection((method) => {
			if (method === "test_method") return { success: true };
			return {};
		});
		const session = new Session("test-1", conn, () => {});
		const result = await session.sendRequest("test_method");
		assert.deepEqual(result, { success: true });
	});
});

