describe("DebugSessionManager", () => {
	it("starts with no sessions", () => {
		const manager = new DebugSessionManager("/tmp");
		assert.equal(manager.sessionCount, 0);
		assert.equal(manager.activeSessionId, null);
	});

	it("registers a session and tracks it as active", () => {
		const manager = new DebugSessionManager("/tmp");
		const conn = createMockConnection();
		const session = new Session("s1", conn, () => {});
		manager.registerSession(session);

		assert.equal(manager.sessionCount, 1);
		assert.equal(manager.activeSessionId, "s1");
	});

	it("getActiveSession returns the active session", () => {
		const manager = new DebugSessionManager("/tmp");
		const conn = createMockConnection();
		const session = new Session("s1", conn, () => {});
		manager.registerSession(session);

		const active = manager.getActiveSession();
		assert.equal(active.sessionId, "s1");
	});

	it("getActiveSession throws when no session is active", () => {
		const manager = new DebugSessionManager("/tmp");
		assert.throws(() => manager.getActiveSession(), /No active debug session/);
	});

	it("stops a session and clears it", async () => {
		const manager = new DebugSessionManager("/tmp");
		const conn = createMockConnection();
		const session = new Session("s1", conn, () => {});
		manager.registerSession(session);

		await manager.stopSession("s1");
		assert.equal(manager.sessionCount, 0);
		assert.equal(manager.activeSessionId, null);
	});

	it("stops active session", async () => {
		const manager = new DebugSessionManager("/tmp");
		const conn = createMockConnection();
		const session = new Session("s1", conn, () => {});
		manager.registerSession(session);

		await manager.stopActiveSession();
		assert.equal(manager.sessionCount, 0);
	});

	it("falls back to another session after stopping active", async () => {
		const manager = new DebugSessionManager("/tmp");
		const conn1 = createMockConnection();
		const conn2 = createMockConnection();
		const s1 = new Session("s1", conn1, () => {});
		const s2 = new Session("s2", conn2, () => {});

		manager.registerSession(s1);
		manager.registerSession(s2);
		assert.equal(manager.activeSessionId, "s2");

		await manager.stopSession("s2");
		assert.equal(manager.activeSessionId, "s1");
	});

	it("stopAll clears everything", async () => {
		const manager = new DebugSessionManager("/tmp");
		const conn1 = createMockConnection();
		const conn2 = createMockConnection();
		manager.registerSession(new Session("s1", conn1, () => {}));
		manager.registerSession(new Session("s2", conn2, () => {}));

		await manager.stopAll();
		assert.equal(manager.sessionCount, 0);
		assert.equal(manager.activeSessionId, null);
	});

	it("listSessions returns all session IDs", () => {
		const manager = new DebugSessionManager("/tmp");
		const conn1 = createMockConnection();
		const conn2 = createMockConnection();
		manager.registerSession(new Session("s1", conn1, () => {}));
		manager.registerSession(new Session("s2", conn2, () => {}));

		const ids = manager.listSessions();
		assert.deepEqual(ids, ["s1", "s2"]);
	});

	it("setActive switches the active session", () => {
		const manager = new DebugSessionManager("/tmp");
		const conn1 = createMockConnection();
		const conn2 = createMockConnection();
		manager.registerSession(new Session("s1", conn1, () => {}));
		manager.registerSession(new Session("s2", conn2, () => {}));

		manager.setActive("s1");
		assert.equal(manager.activeSessionId, "s1");
	});

	it("setActive throws for unknown session", () => {
		const manager = new DebugSessionManager("/tmp");
		assert.throws(() => manager.setActive("unknown"), /not found/);
	});

	it("getSession returns undefined for unknown ID", () => {
		const manager = new DebugSessionManager("/tmp");
		assert.equal(manager.getSession("unknown"), undefined);
	});
});

