describe("stepping", () => {
	it("maps continue to correct DAP method", async () => {
		const session = createMockSession((method, params) => {
			assert.equal(method, "continue");
			assert.equal((params as { threadId: number }).threadId, 1);
			return {};
		});
		const result = await stepping(session, { action: "continue" });
		assert.equal(result.success, true);
	});

	it("maps stepOver to 'next' DAP method", async () => {
		const session = createMockSession((method) => {
			assert.equal(method, "next");
			return {};
		});
		const result = await stepping(session, { action: "stepOver" });
		assert.equal(result.success, true);
	});

	it("maps stepInto to 'stepIn' DAP method", async () => {
		const session = createMockSession((method) => {
			assert.equal(method, "stepIn");
			return {};
		});
		const result = await stepping(session, { action: "stepInto" });
		assert.equal(result.success, true);
	});

	it("maps stepOut to 'stepOut' DAP method", async () => {
		const session = createMockSession((method) => {
			assert.equal(method, "stepOut");
			return {};
		});
		const result = await stepping(session, { action: "stepOut" });
		assert.equal(result.success, true);
	});

	it("uses provided threadId", async () => {
		const session = createMockSession((method, params) => {
			assert.equal((params as { threadId: number }).threadId, 42);
			return {};
		});
		const result = await stepping(session, { action: "continue", threadId: 42 });
		assert.equal(result.success, true);
	});

	it("returns failure on connection error", async () => {
		const session = createMockSession(() => {
			throw new Error("Connection lost");
		});
		const result = await stepping(session, { action: "continue" });
		assert.equal(result.success, false);
		assert.ok(result.message?.includes("Connection lost"));
	});
});

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { evaluate } from "../../src/features/evaluate.ts";
import type { Session } from "../../src/client/session.ts";
import type { Connection } from "../../src/client/connection.ts";

function createMockSession(requestHandler: (method: string, params?: Record<string, unknown>) => Record<string, unknown>): Session {
	const conn: Connection = {
		isClosed: false,
		transportType: "stdio" as const,
		async sendRequest(method: string, params?: Record<string, unknown>): Promise<Record<string, unknown>> {
			return requestHandler(method, params);
		},
		sendNotification(): void {},
		kill(): void {},
		startStdio(): void {},
		connectTcp(): Promise<void> { return Promise.resolve(); },
	} as unknown as Connection;
	return new Session("test", conn, () => {});
}

describe("evaluate", () => {
	it("sends evaluate request with correct params", async () => {
		const session = createMockSession((method, params) => {
			assert.equal(method, "evaluate");
			const p = params as { expression: string; context: string; frameId?: number };
			assert.equal(p.expression, "x + 1");
			assert.equal(p.context, "repl");
			assert.equal(p.frameId, undefined);
			return {
				result: "43",
				type: "number",
				variablesReference: 0,
			};
		});

		const result = await evaluate(session, { expression: "x + 1" });
		assert.equal(result.result, "43");
		assert.equal(result.type, "number");
		assert.equal(result.variablesReference, 0);
	});

	it("includes frameId when provided", async () => {
		const session = createMockSession((method, params) => {
			const p = params as { frameId?: number };
			assert.equal(p.frameId, 5);
			return { result: "true", variablesReference: 0 };
		});

		await evaluate(session, { expression: "ok", frameId: 5 });
	});

	it("uses provided context", async () => {
		const session = createMockSession((method, params) => {
			const p = params as { context: string };
			assert.equal(p.context, "watch");
			return { result: "42", variablesReference: 0 };
		});

		await evaluate(session, { expression: "x", context: "watch" });
	});

	it("handles error responses gracefully", async () => {
		const session = createMockSession(() => {
			throw new Error("Cannot evaluate");
		});

		await assert.rejects(
			() => evaluate(session, { expression: "bad" }),
			/Cannot evaluate/,
		);
	});
});

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { AdapterRegistry } from "../../src/adapters/registry.ts";

describe("AdapterRegistry", () => {
	it("resolves .ts files to typescript adapter", () => {
		const registry = new AdapterRegistry();
		const adapter = registry.resolve("test.ts");
		assert.ok(adapter);
		assert.equal(adapter.language, "typescript");
		assert.equal(adapter.adapter, "js-debug");
		assert.equal(adapter.transport, "stdio");
	});

	it("resolves .js files to javascript adapter", () => {
		const registry = new AdapterRegistry();
		const adapter = registry.resolve("app.js");
		assert.ok(adapter);
		assert.equal(adapter.language, "javascript");
	});

	it("resolves .mjs files to javascript adapter", () => {
		const registry = new AdapterRegistry();
		const adapter = registry.resolve("module.mjs");
		assert.ok(adapter);
		assert.equal(adapter.language, "javascript");
	});

	it("resolves .py files to python adapter", () => {
		const registry = new AdapterRegistry();
		const adapter = registry.resolve("script.py");
		assert.ok(adapter);
		assert.equal(adapter.language, "python");
		assert.equal(adapter.adapter, "debugpy");
		assert.equal(adapter.transport, "tcp");
	});

	it("returns undefined for unknown extensions", () => {
		const registry = new AdapterRegistry();
		const adapter = registry.resolve("main.go");
		assert.equal(adapter, undefined);
	});

	it("resolves adapter by name", () => {
		const registry = new AdapterRegistry();
		const adapter = registry.getByName("node");
		assert.ok(adapter);
		assert.equal(adapter.language, "javascript");
	});

	it("resolves adapter by language name", () => {
		const registry = new AdapterRegistry();
		const adapter = registry.getByName("python");
		assert.ok(adapter);
		assert.equal(adapter.language, "python");
	});

	it("custom adapters override built-in for same extension", () => {
		const registry = new AdapterRegistry({
			"my-python": {
				language: "python-custom",
				command: ["my-debugger"],
				adapter: "my-debugger",
				extensions: [".py"],
				transport: "stdio",
				enabled: true,
			},
		});
		const adapter = registry.resolve("test.py");
		assert.ok(adapter);
		assert.equal(adapter.adapter, "my-debugger");
		assert.equal(adapter.language, "python-custom");
	});

	it("getAll returns all adapters", () => {
		const registry = new AdapterRegistry();
		const all = registry.getAll();
		assert.ok(all.length >= 3); // js, ts, py at minimum
	});

	it("custom disabled adapter is skipped", () => {
		const registry = new AdapterRegistry({
			"disabled-adapter": {
				command: ["test"],
				extensions: [".xyz"],
				transport: "stdio",
				enabled: false,
			},
		});
		const adapter = registry.resolve("file.xyz");
		assert.equal(adapter, undefined);
	});

	it("custom adapter without required fields is skipped", () => {
		const registry = new AdapterRegistry({
			"incomplete": {
				extensions: [".abc"],
				transport: "stdio",
				// Missing command
			},
		});
		const adapter = registry.resolve("file.abc");
		assert.equal(adapter, undefined);
	});
});

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { loadConfig } from "../../src/config.ts";
import { mkdirSync, rmSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";

describe("loadConfig", () => {
	const testDir = join(tmpdir(), "pi-debug-test-config");

	it("returns defaults when no config file exists", () => {
		const { config, path } = loadConfig("/nonexistent");
		assert.equal(path, null);
		assert.equal(config.enabled, true);
		assert.equal(config.autoSuggest, true);
		assert.equal(config.defaultAdapter, "auto");
		assert.equal(config.stopOnEntry, true);
		assert.equal(config.maxStackFrames, 50);
		assert.equal(config.maxVariableDepth, 3);
		assert.equal(config.timeout, 30000);
	});

	it("loads config from .pi/pi-debug.json", () => {
		const configDir = join(testDir, ".pi");
		try {
			mkdirSync(configDir, { recursive: true });
			writeFileSync(
				join(configDir, "pi-debug.json"),
				JSON.stringify({ enabled: false, timeout: 60000 }),
			);

			const { config, path } = loadConfig(testDir);
			assert.ok(path);
			assert.equal(config.enabled, false);
			assert.equal(config.timeout, 60000);
			// Defaults preserved for unset fields
			assert.equal(config.maxStackFrames, 50);
		} finally {
			rmSync(testDir, { recursive: true, force: true });
		}
	});

	it("handles malformed JSON gracefully", () => {
		const configDir = join(testDir, ".pi");
		try {
			mkdirSync(configDir, { recursive: true });
			writeFileSync(join(configDir, "pi-debug.json"), "{invalid}");

			const { config } = loadConfig(testDir);
			// Should fall back to defaults
			assert.equal(config.enabled, true);
		} finally {
			rmSync(testDir, { recursive: true, force: true });
		}
	});
});

